import React, { useRef } from "react";
import { motion, useInView } from "framer-motion";
import { projects } from "../data/portfolioData";

export default function Projects() {
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true });

  return (
    <section id="projects" className="py-40 px-6 bg-[#050505]">
      <div className="max-w-7xl mx-auto">

        {/* Header */}
        <motion.div
          ref={ref}
          initial={{ opacity: 0, y: 30 }}
          animate={isInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.8 }}
          className="mb-32"
        >
          <span className="uppercase tracking-[0.25em] text-slate-500 text-sm">
            Selected Work
          </span>

          <h2 className="text-white font-bold mt-4 leading-none text-[clamp(4rem,10vw,8rem)]">
            Projects
          </h2>

          <p className="text-slate-400 text-lg mt-8 max-w-2xl">
            AI systems, agentic workflows, machine learning infrastructure,
            and financial intelligence platforms built for real-world deployment.
          </p>
        </motion.div>

        {/* Projects */}
        <div className="space-y-40">
          {projects.map((project, index) => (
            <motion.div
              key={project.id}
              initial={{ opacity: 0, y: 40 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.8 }}
            >
              <div className="grid lg:grid-cols-2 gap-20 items-center">

                {/* Left Content */}
                <div>
                  <span className="text-slate-600 text-sm tracking-widest">
                    0{index + 1}
                  </span>

                  <h3 className="text-white text-5xl font-bold mt-4 mb-6">
                    {project.name}
                  </h3>

                  <p className="text-slate-400 text-lg leading-relaxed mb-8">
                    {project.description}
                  </p>

                  <div className="flex flex-wrap gap-2 mb-8">
                    {project.tech?.slice(0, 8).map((tech) => (
                      <span
                        key={tech}
                        className="px-3 py-1 rounded-full bg-white/5 border border-white/10 text-slate-300 text-sm"
                      >
                        {tech}
                      </span>
                    ))}
                  </div>

                  {project.github && (
                    <a
                      href={project.github}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="inline-flex items-center gap-2 text-white hover:text-[#6c63ff] transition"
                    >
                      View Project →
                    </a>
                  )}
                </div>

                {/* Right Showcase */}
                <div>
                  <div className="rounded-[32px] overflow-hidden border border-white/5 bg-[#0f0f0f] h-[500px] flex items-center justify-center">

                    <div className="text-center px-10">

                      <div className="text-7xl mb-6">
                        {index === 0
                          ? "🤖"
                          : index === 1
                          ? "🛡️"
                          : "📈"}
                      </div>

                      <h4 className="text-white text-2xl font-bold mb-4">
                        {project.name}
                      </h4>

                      <p className="text-slate-500 max-w-sm mx-auto">
                        Project showcase preview. Replace this section with a
                        custom screenshot or Figma mockup for a premium portfolio look.
                      </p>

                    </div>

                  </div>
                </div>

              </div>
            </motion.div>
          ))}
        </div>

      </div>
    </section>
  );
}
